106		if resp.Data.DocumentByPath.Content == nil || !strings.Contains(*resp.Data.DocumentByPath.Content, "Beta B") {
107			t.Fatalf("scoped B query: expected B's content, got %+v", resp.Data.DocumentByPath)
108		}
109	
110		// 2. Asking the scoped B endpoint for A's document path must NOT find it
111		//    (resolves to null since A's doc does not exist under B's project root).
112		queryAOnB := `{ documentByPath(path: "` + filepath.ToSlash(relA) + `") { id path content } }`
113		w2 := postGraphQL(t, srv, "/api/projects/"+entryB.ID+"/graphql", queryAOnB)
114		if w2.Code != http.StatusOK {
115			t.Fatalf("cross-project leak query: status=%d body=%s", w2.Code, w2.Body.String())
116		}
117		var resp2 struct {
118			Data struct {
119				DocumentByPath *struct {
120					ID      string  `json:"id"`
121					Content *string `json:"content"`
122				} `json:"documentByPath"`
123			} `json:"data"`
124		}
125		_ = json.Unmarshal(w2.Body.Bytes(), &resp2)
126		if resp2.Data.DocumentByPath != nil {
127			// If non-null and content contains A's title, that's the leak we're
128			// guarding against. The naming `relA` happens to equal `relB` so this
129			// also implicitly proves we're not reading from project A's filesystem.
130			if resp2.Data.DocumentByPath.Content != nil && strings.Contains(*resp2.Data.DocumentByPath.Content, "Alpha A") {
131				t.Fatalf("CROSS-PROJECT LEAK: scoped B endpoint returned A's content: %+v", resp2.Data.DocumentByPath)
132			}
133		}
134	}
