197	func newFixtureRepo(t *testing.T, profile string) string {
198		t.Helper()
199	
200		root := repoRoot(t)
201		script := filepath.Join(root, "scripts", "build-fixture-repo.sh")
202		if _, err := os.Stat(script); err != nil {
203			t.Fatalf("fixture script not found at %s: %v", script, err)
204		}
205	
206		dest := t.TempDir()
207		bin := resolveDDxBinary(t, root)
208	
209		cmd := exec.Command("bash", script, dest, "--profile", profile)
210		cmd.Env = append(os.Environ(), "DDX_BIN="+bin)
211		var stderr bytes.Buffer
212		cmd.Stderr = &stderr
213		cmd.Stdout = &stderr
214		if err := cmd.Run(); err != nil {
215			t.Fatalf("build-fixture-repo.sh failed (profile=%s): %v\n%s", profile, err, stderr.String())
216		}
217		return dest
218	}
219	
220	func repoRoot(t *testing.T) string {
221		t.Helper()
222		_, file, _, ok := runtime.Caller(0)
223		if !ok {
224			t.Fatal("runtime.Caller failed")
225		}
226		dir := filepath.Dir(file)
227		for {
228			if _, err := os.Stat(filepath.Join(dir, "scripts", "build-fixture-repo.sh")); err == nil {
229				return dir
230			}
231			parent := filepath.Dir(dir)
232			if parent == dir {
233				t.Fatal("could not locate repo root from " + file)
234			}
235			dir = parent
236		}
237	}
