239	var (
240		ddxBuildOnce sync.Once
241		ddxBuildPath string
242		ddxBuildErr  error
243	)
244	
245	func resolveDDxBinary(t *testing.T, root string) string {
246		t.Helper()
247		if env := os.Getenv("DDX_BIN"); env != "" {
248			return env
249		}
250		if path, err := exec.LookPath("ddx"); err == nil {
251			return path
252		}
253	
254		ddxBuildOnce.Do(func() {
255			dir, err := os.MkdirTemp("", "ddx-fixture-bin-")
256			if err != nil {
257				ddxBuildErr = err
258				return
259			}
260			out := filepath.Join(dir, "ddx")
261			cmd := exec.Command("go", "build", "-o", out, ".")
262			cmd.Dir = filepath.Join(root, "cli")
263			var stderr bytes.Buffer
264			cmd.Stderr = &stderr
265			if err := cmd.Run(); err != nil {
266				ddxBuildErr = err
267				ddxBuildPath = stderr.String()
268				return
269			}
270			ddxBuildPath = out
271		})
272		if ddxBuildErr != nil {
273			t.Fatalf("could not build ddx binary for fixture: %v\n%s", ddxBuildErr, ddxBuildPath)
274		}
275		return ddxBuildPath
276	}
